select v_1 as "o_orderpriority", v_2 as "order_count" from (select v_3 as v_1, count(*) as v_2 from (select * from (select * from (select "o_orderkey" as v_4, "o_custkey" as v_5, "o_orderstatus" as v_6, "o_totalprice" as v_7, "o_orderdate" as v_8, "o_orderpriority" as v_3, "o_clerk" as v_9, "o_shippriority" as v_10, "o_comment" as v_11 from "orders") s where (v_8 >= (date('1993-07-01', '+0 seconds'))) and (v_8 < (date('1993-07-01', '+3 months')))) l where exists(select * from (select * from (select "l_orderkey" as v_12, "l_partkey" as v_13, "l_suppkey" as v_14, "l_linenumber" as v_15, "l_quantity" as v_16, "l_extendedprice" as v_17, "l_discount" as v_18, "l_tax" as v_19, "l_returnflag" as v_20, "l_linestatus" as v_21, "l_shipdate" as v_22, "l_commitdate" as v_23, "l_receiptdate" as v_24, "l_shipinstruct" as v_25, "l_shipmode" as v_26, "l_comment" as v_27 from "lineitem") s where v_23 < v_24) r where v_12 = v_4)) s group by 1) s order by v_1
